const express = require('express');
const sgMail = require('@sendgrid/mail');

// Load SendGrid API key from environment variable - NEVER hardcode secrets
const SENDGRID_API_KEY = process.env.SENDGRID_API_KEY;

if (!SENDGRID_API_KEY) {
  console.error(
    'FATAL: SENDGRID_API_KEY environment variable is not set. ' +
    'Please set it before starting the application. ' +
    'Example: export SENDGRID_API_KEY=your_key_here'
  );
  process.exit(1);
}

sgMail.setApiKey(SENDGRID_API_KEY);

const app = express();
app.use(express.json());

/**
 * Validates an email address format.
 */
function isValidEmail(email) {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return typeof email === 'string' && emailRegex.test(email);
}

/**
 * Sanitizes a string to prevent injection in email content.
 */
function sanitizeString(str) {
  if (typeof str !== 'string') return '';
  return str
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

/**
 * Sends an email notification via SendGrid.
 *
 * @param {Object} options
 * @param {string} options.to - Recipient email address
 * @param {string} options.from - Sender email address
 * @param {string} options.subject - Email subject
 * @param {string} options.text - Plain text body
 * @param {string} [options.html] - Optional HTML body
 * @returns {Promise<Object>} SendGrid API response
 */
async function sendEmailNotification({ to, from, subject, text, html }) {
  if (!isValidEmail(to)) {
    throw new Error(`Invalid recipient email address: ${sanitizeString(to)}`);
  }

  if (!isValidEmail(from)) {
    throw new Error(`Invalid sender email address: ${sanitizeString(from)}`);
  }

  if (!subject || typeof subject !== 'string' || subject.trim().length === 0) {
    throw new Error('Subject is required and must be a non-empty string.');
  }

  if (!text || typeof text !== 'string' || text.trim().length === 0) {
    throw new Error('Text body is required and must be a non-empty string.');
  }

  const msg = {
    to: to.trim(),
    from: from.trim(),
    subject: subject.trim(),
    text: text.trim(),
  };

  if (html && typeof html === 'string' && html.trim().length > 0) {
    msg.html = html.trim();
  }

  try {
    const response = await sgMail.send(msg);
    console.log(`Email sent successfully to ${to}, status: ${response[0].statusCode}`);
    return {
      success: true,
      statusCode: response[0].statusCode,
      messageId: response[0].headers['x-message-id'] || null,
    };
  } catch (error) {
    console.error('SendGrid email send failed:', {
      message: error.message,
      code: error.code,
      response: error.response ? {
        statusCode: error.response.statusCode,
        body: error.response.body,
      } : undefined,
    });
    throw error;
  }
}

/**
 * POST /api/send-notification
 *
 * Request body:
 * {
 *   "to": "recipient@example.com",
 *   "from": "devops@example.com",
 *   "subject": "Deployment Notification",
 *   "text": "Deployment completed successfully.",
 *   "html": "<p>Deployment completed <strong>successfully</strong>.</p>"  // optional
 * }
 */
app.post('/api/send-notification', async (req, res) => {
  const { to, from, subject, text, html } = req.body;

  if (!to || !from || !subject || !text) {
    return res.status(400).json({
      success: false,
      error: 'Missing required fields: to, from, subject, and text are all required.',
    });
  }

  try {
    const result = await sendEmailNotification({ to, from, subject, text, html });
    return res.status(200).json(result);
  } catch (error) {
    const statusCode = error.response?.statusCode || 500;
    return res.status(statusCode).json({
      success: false,
      error: error.message || 'Failed to send email notification.',
    });
  }
});

/**
 * GET /api/health
 * Health check endpoint.
 */
app.get('/api/health', (req, res) => {
  res.status(200).json({
    status: 'healthy',
    sendgridConfigured: !!SENDGRID_API_KEY,
    timestamp: new Date().toISOString(),
  });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Email notification service running on port ${PORT}`);
  console.log('SendGrid API key is configured from environment variable.');
});

module.exports = { app, sendEmailNotification };